#include <stdio.h>
int main() {
    int T, N, ai;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int xor = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &ai);
            xor ^= ai;
        }
        if (xor == 0) {
            printf("Second\n");
        } else {
            printf("First\n");
        }
    }
    return 0;
}

