const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const ai = readline().split(' ').map(x => parseInt(x));
    let xor = 0;
    for (let j = 0; j < N; j++) {
        xor ^= ai[j];
    }
    if (xor == 0) {
        console.log('Second');
    } else {
        console.log('First');
    }
}
